302	    }
303	  } finally {
304	    stopKeyListener();
305	    process.stdout.write(SHOW_CURSOR);
306	  }
307	
308	  // ── 总结 ──
309	  console.log();
310	  console.log(`  ${BOLD}本轮总结${RESET}`);
311	  console.log(`  ${"─".repeat(24)}`);
312	  console.log(`  完成番茄: ${GREEN}${completedCycles}${RESET}`);
313	  console.log(`  总专注:   ${GREEN}${completedCycles * opts.work}${RESET} 分钟`);
